member.example:
Bind the TMP_Text font size using a serialized binder field — the target TMP_Text is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TextFontSizeBinder _fontSize;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _fontSize;
    }


Bind the TMP_Text font size by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _target;
        
        private TextFontSizeBinder FontSize =>
            new(_target);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _fontSize;
    }

Switch the TMP_Text font size between two values using a serialized binder field — the target TMP_Text is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TextFontSizeSwitcherBinder _isLarge;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isLarge;
    }


Switch the TMP_Text font size between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _target;
        
        private TextFontSizeSwitcherBinder IsLarge => new(
            _target, trueValue: 24f, falseValue: 14f);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isLarge;
    }
